import{_ as i,o as a,c as o,ai as r}from"./chunks/framework.CaiDwmc7.js";const c=JSON.parse('{"title":"技术面试：自我介绍与项目讲述","description":"","frontmatter":{},"headers":[],"relativePath":"resume/interview-skills.md","filePath":"resume/interview-skills.md"}'),t={name:"resume/interview-skills.md"};function e(n,l,s,h,u,d){return a(),o("div",null,[...l[0]||(l[0]=[r('<h1 id="技术面试-自我介绍与项目讲述" tabindex="-1">技术面试：自我介绍与项目讲述 <a class="header-anchor" href="#技术面试-自我介绍与项目讲述" aria-label="Permalink to “技术面试：自我介绍与项目讲述”">​</a></h1><blockquote><p>针对小公司技术面试的准备指南：简单自我介绍 → 根据项目经验/简历提问</p></blockquote><hr><h2 id="🗣️-一、技术面试开场-自我介绍-2-3分钟" tabindex="-1">🗣️ 一、技术面试开场：自我介绍（2-3分钟） <a class="header-anchor" href="#🗣️-一、技术面试开场-自我介绍-2-3分钟" aria-label="Permalink to “🗣️ 一、技术面试开场：自我介绍（2-3分钟）”">​</a></h2><p><strong>核心策略</strong>：小公司的技术面试通常直接进入正题，自我介绍要<strong>简洁有力</strong>，突出技术栈和项目经验，引导面试官提问你准备充分的领域。</p><h3 id="💡-自我介绍的核心目的" tabindex="-1">💡 自我介绍的核心目的 <a class="header-anchor" href="#💡-自我介绍的核心目的" aria-label="Permalink to “💡 自我介绍的核心目的”">​</a></h3><p>在短短 2-3 分钟内：</p><ol><li><strong>展示技术栈</strong>：让面试官知道你会什么</li><li><strong>突出项目经验</strong>：说明你做过什么，有什么成果</li><li><strong>体现交付能力</strong>：让面试官相信你能在中小团队“接得住活、交得出结果”</li><li><strong>建立沟通预期</strong>：明确你希望从“最近的项目/模块”开始聊</li></ol><h3 id="📝-高分话术模板-基于8年-经验-全栈开发" tabindex="-1">📝 高分话术模板（基于8年+经验，全栈开发） <a class="header-anchor" href="#📝-高分话术模板-基于8年-经验-全栈开发" aria-label="Permalink to “📝 高分话术模板（基于8年+经验，全栈开发）”">​</a></h3><p>下面给你两份可以直接背的版本：<strong>远程线上面试</strong>与<strong>线下面试</strong>（都不强调“技术诱饵”，更贴合中小企业的交付场景）。</p><h4 id="版本-a-远程线上面试自我介绍-2-分钟左右" tabindex="-1">版本 A：远程线上面试自我介绍（2 分钟左右） <a class="header-anchor" href="#版本-a-远程线上面试自我介绍-2-分钟左右" aria-label="Permalink to “版本 A：远程线上面试自我介绍（2 分钟左右）”">​</a></h4><blockquote><p><strong>1. 极简开场（20秒）</strong><br> “面试官您好，我叫张孟杰，很高兴参加这次面试。我有 8 年多 Java 开发经验，近一年在杭州一家公司做远程全栈开发。”</p><p><strong>2. 我能交付什么（40秒）</strong><br> “我平时主要负责需求梳理、接口开发、前后端联调、上线部署和运维，能独立把一个模块从 0 到 1 做完并稳定跑起来，比较适合中小团队快节奏的交付。”</p><p><strong>3. 技术栈概览（40秒）</strong><br> “后端主要是 Spring Boot + MyBatis，数据库以 MySQL 为主，会做表结构设计、索引优化和慢查询排查；Redis 主要用于基础缓存和分布式锁场景。前端主要用 Vue + TypeScript 做管理端。部署方面熟悉 Linux 和 Docker，能写 Dockerfile、处理端口/日志/环境配置这些上线问题。”</p><p><strong>4. 项目经历（20秒）</strong><br> “项目上，我做过悟空 CRM/ERP 这类企业管理系统的核心模块交付；最近这份远程工作里，我独立完成物联网设备相关的 Web 管理端和小程序后台，包含数据库设计、接口开发、部署上线和日常维护。”</p><p>“以上是我的基本情况，您可以直接从我最近的物联网项目或 CRM/ERP 的某个模块开始问。”</p></blockquote><h4 id="可选插入段-保留你之前-经历讲得很顺-的版本" tabindex="-1">可选插入段（保留你之前“经历讲得很顺”的版本） <a class="header-anchor" href="#可选插入段-保留你之前-经历讲得很顺-的版本" aria-label="Permalink to “可选插入段（保留你之前“经历讲得很顺”的版本）”">​</a></h4><blockquote><p>你可以把下面这段，插到 <strong>版本 A / 版本 B</strong> 的「技术栈概览」之后（更偏“简历口吻”，也更像你之前那段）：</p><p>“在技术栈方面，我从 2016 年开始做 Java 开发，经历过从传统单体到微服务化的演进。当前我更常用的组合是：</p><ul><li><strong>后端</strong>：Spring Boot、MyBatis、Redis</li><li><strong>前端</strong>：Vue / React、TypeScript</li><li><strong>部署运维</strong>：Linux、Docker（包含环境配置、日志排查、容器化部署）</li></ul><p>在项目经历方面：</p><ul><li>之前在卡卡罗特公司主要做悟空 CRM/ERP 这类系统，负责核心业务模块的设计与开发，也参与过服务拆分、注册配置、任务调度等配套能力的落地。</li><li>现在这份远程工作里，我更多是独立负责物联网设备相关的前后端开发，包含数据库设计、接口开发、联调、部署上线和日常维护。”</li></ul></blockquote><h4 id="版本-b-线下面试自我介绍-2-分钟左右" tabindex="-1">版本 B：线下面试自我介绍（2 分钟左右） <a class="header-anchor" href="#版本-b-线下面试自我介绍-2-分钟左右" aria-label="Permalink to “版本 B：线下面试自我介绍（2 分钟左右）”">​</a></h4><blockquote><p>“面试官您好，我叫张孟杰，感谢给我这次机会。我有 8 年多 Java 开发经验，做过后端也做过前端，最近一年是远程全栈，平时负责从需求确认、开发联调到部署上线的完整流程。”</p><p>“技术上我后端主要是 Spring Boot + MyBatis，MySQL 用得比较多，能做表设计、索引优化、慢查询排查；Redis 主要用于缓存和并发控制。前端用 Vue + TypeScript，能把管理后台页面和接口联调跑通。部署运维这块熟悉 Linux 和 Docker，日常能处理日志、配置、端口、重启、回滚这些事情。”</p><p>“我做过的项目以中小企业业务系统为主，比如 CRM/ERP/OA，也做过物联网相关平台。我的优势是上手快、能独立推进、遇到线上问题能定位原因并给出落地方案，同时沟通协作比较顺畅。”</p><p>“我希望今天能把岗位的业务和技术栈确认清楚，看看我能在哪些模块最快产出价值。您可以从我最近做的项目开始问。”</p></blockquote><blockquote><p>⚠️ 小提示：自我介绍里不要主动抛你没在项目里稳定用过的点（例如某些复杂中间件/分布式事务）。<strong>说你真正做过的交付闭环</strong>，约面与通过率更高。</p></blockquote><hr><h2 id="💼-二、项目讲述-用star法则包装" tabindex="-1">💼 二、项目讲述：用STAR法则包装 <a class="header-anchor" href="#💼-二、项目讲述-用star法则包装" aria-label="Permalink to “💼 二、项目讲述：用STAR法则包装”">​</a></h2><h3 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to “核心原则”">​</a></h3><p><strong>小公司的技术面试，面试官最关心的是：</strong></p><ul><li>你能不能独立完成开发？</li><li>你解决过什么技术问题？</li><li>你对技术栈的掌握程度？</li></ul><p><strong>所以项目讲述要：</strong></p><ul><li>突出<strong>技术亮点</strong>，而不是业务功能</li><li>用<strong>具体数据</strong>说话（响应时间、QPS、优化效果）</li><li>准备<strong>技术细节</strong>，能回答深入问题</li></ul><h3 id="📝-项目讲述模板-star法则" tabindex="-1">📝 项目讲述模板（STAR法则） <a class="header-anchor" href="#📝-项目讲述模板-star法则" aria-label="Permalink to “📝 项目讲述模板（STAR法则）”">​</a></h3><h4 id="模板结构" tabindex="-1">模板结构 <a class="header-anchor" href="#模板结构" aria-label="Permalink to “模板结构”">​</a></h4><ul><li><strong>S（Situation 情境）</strong>：项目背景、业务场景、遇到的技术挑战</li><li><strong>T（Task 任务）</strong>：你需要完成什么目标</li><li><strong>A（Action 行动）</strong>：你用了什么技术方案、解决了什么问题</li><li><strong>R（Result 结果）</strong>：取得了什么可量化的效果</li></ul><h4 id="示例-数据库优化项目" tabindex="-1">示例：数据库优化项目 <a class="header-anchor" href="#示例-数据库优化项目" aria-label="Permalink to “示例：数据库优化项目”">​</a></h4><p><strong>❌ 烂大街写法</strong>：</p><blockquote><p>&quot;我在项目中优化过SQL查询，加了索引，查询变快了。&quot;</p></blockquote><p><strong>✅ 高大上包装</strong>：</p><blockquote><p>&quot;在悟空CRM系统中，我负责订单查询模块的开发。初期发现订单列表查询接口响应很慢，特别是在数据量大的时候，查询时间达到5-8秒，严重影响用户体验。</p><p>我通过慢查询日志和EXPLAIN执行计划分析，发现了几个问题：</p><ol><li>联合索引的最左前缀法则失效，导致全表扫描</li><li>深分页查询（LIMIT 10000, 20）性能极差</li><li>有隐式类型转换导致索引失效</li></ol><p>我的解决方案：</p><ol><li>重新设计索引，遵循最左前缀原则</li><li>使用延迟关联（子查询先查主键）优化深分页</li><li>避免类型转换，统一字段类型</li></ol><p>最终效果：查询时间从5-8秒优化到200ms以内，用户体验大幅提升。&quot;</p></blockquote><p><strong>可能被问到的深入问题</strong>：</p><ul><li>&quot;你是怎么分析慢查询的？EXPLAIN的各个字段是什么意思？&quot;</li><li>&quot;最左前缀法则具体是什么？能举个例子吗？&quot;</li><li>&quot;延迟关联的原理是什么？为什么能优化深分页？&quot;</li></ul><hr><h2 id="🎯-三、技术面试常见问题准备" tabindex="-1">🎯 三、技术面试常见问题准备 <a class="header-anchor" href="#🎯-三、技术面试常见问题准备" aria-label="Permalink to “🎯 三、技术面试常见问题准备”">​</a></h2><h3 id="基于当前简历可能被问到的问题" tabindex="-1">基于当前简历可能被问到的问题 <a class="header-anchor" href="#基于当前简历可能被问到的问题" aria-label="Permalink to “基于当前简历可能被问到的问题”">​</a></h3><h4 id="_1-你8年经验-为什么期望薪资只有6-10k" tabindex="-1">1. &quot;你8年经验，为什么期望薪资只有6-10k？&quot; <a class="header-anchor" href="#_1-你8年经验-为什么期望薪资只有6-10k" aria-label="Permalink to “1. &quot;你8年经验，为什么期望薪资只有6-10k？&quot;”">​</a></h4><p><strong>回答策略</strong>：</p><ul><li>&quot;我更看重远程工作的灵活性和成长空间。薪资不是唯一考虑因素，如果平台好、技术氛围好，我愿意接受合理的薪资范围。&quot;</li><li>&quot;我目前是远程工作，生活成本相对较低，所以对薪资的要求比较务实。&quot;</li><li>&quot;我更希望找到一个能让我持续学习和成长的机会。&quot;</li></ul><h4 id="_2-你技术栈跨度这么大-你最熟悉哪个" tabindex="-1">2. &quot;你技术栈跨度这么大，你最熟悉哪个？&quot; <a class="header-anchor" href="#_2-你技术栈跨度这么大-你最熟悉哪个" aria-label="Permalink to “2. &quot;你技术栈跨度这么大，你最熟悉哪个？&quot;”">​</a></h4><p><strong>回答策略</strong>：</p><ul><li>&quot;我最熟悉的是以 Spring Boot + MyBatis + MySQL + Redis 为主的这一套，因为最近几年一直在做中小企业业务系统和物联网项目。Struts2/Hibernate 更多是早期项目里用到，现在基本不会在新项目里使用了。&quot;</li><li>&quot;技术栈的演进是正常的，我也在持续用业余时间学习新的框架和工具，但简历上写的都是我在项目中真正用过、能独立交付的技术。&quot;</li><li>&quot;现在日常开发主要是 Spring Boot 做后端、Vue 做管理端、Docker + Linux 做部署，这一整套我比较熟。&quot;</li></ul><h4 id="_3-你做过高并发项目吗" tabindex="-1">3. &quot;你做过高并发项目吗？&quot; <a class="header-anchor" href="#_3-你做过高并发项目吗" aria-label="Permalink to “3. &quot;你做过高并发项目吗？&quot;”">​</a></h4><p><strong>回答策略</strong>：</p><ul><li>&quot;我做的项目主要是业务系统，虽然没有特别高的并发量，但我注重性能优化。比如用Redis做缓存、优化SQL查询、使用异步处理等。&quot;</li><li>&quot;如果有机会，我很愿意参与高并发项目的开发，这也是我学习的方向。&quot;</li><li>&quot;虽然业务系统并发量不是特别高，但我用Redis做缓存、优化数据库查询、使用消息队列做异步处理，这些技术在高并发场景下同样适用。&quot;</li></ul><h4 id="_4-你为什么频繁换工作" tabindex="-1">4. &quot;你为什么频繁换工作？&quot; <a class="header-anchor" href="#_4-你为什么频繁换工作" aria-label="Permalink to “4. &quot;你为什么频繁换工作？&quot;”">​</a></h4><p><strong>回答策略</strong>：</p><ul><li>&quot;我换工作主要是为了技术成长和更好的发展机会。从传统SSH到微服务架构，我需要找到能让我学习新技术的平台。&quot;</li><li>&quot;目前我在远程工作，工作稳定，已经做了快1年了。&quot;</li><li>&quot;每次换工作都是经过慎重考虑的，主要是为了技术成长和更好的发展机会。&quot;</li></ul><h4 id="_5-你远程工作-怎么保证沟通和协作" tabindex="-1">5. &quot;你远程工作，怎么保证沟通和协作？&quot; <a class="header-anchor" href="#_5-你远程工作-怎么保证沟通和协作" aria-label="Permalink to “5. &quot;你远程工作，怎么保证沟通和协作？&quot;”">​</a></h4><p><strong>回答策略</strong>：</p><ul><li>&quot;我有丰富的远程工作经验，会定期汇报进度，主动沟通问题。&quot;</li><li>&quot;我使用Git、项目管理工具、即时通讯工具等，保证沟通顺畅。&quot;</li><li>&quot;我会按时交付，代码质量稳定，自驱力强。&quot;</li><li>&quot;我会主动反馈问题，不会等到deadline才说有问题。&quot;</li></ul><hr><h2 id="📋-四、技术面试准备清单" tabindex="-1">📋 四、技术面试准备清单 <a class="header-anchor" href="#📋-四、技术面试准备清单" aria-label="Permalink to “📋 四、技术面试准备清单”">​</a></h2><h3 id="技术栈深度准备-结合你当前简历" tabindex="-1">技术栈深度准备（结合你当前简历） <a class="header-anchor" href="#技术栈深度准备-结合你当前简历" aria-label="Permalink to “技术栈深度准备（结合你当前简历）”">​</a></h3><h4 id="spring-spring-boot" tabindex="-1">Spring / Spring Boot <a class="header-anchor" href="#spring-spring-boot" aria-label="Permalink to “Spring / Spring Boot”">​</a></h4><ul><li>[ ] IoC 容器、Bean 生命周期</li><li>[ ] AOP 原理、动态代理</li><li>[ ] Spring 事务传播行为、常见失效场景</li><li>[ ] Spring Boot 自动配置原理、大致启动流程</li></ul><h4 id="mybatis" tabindex="-1">MyBatis <a class="header-anchor" href="#mybatis" aria-label="Permalink to “MyBatis”">​</a></h4><ul><li>[ ] MyBatis的执行流程</li><li>[ ] #{}和${}的区别</li><li>[ ] 一级缓存、二级缓存</li><li>[ ] 动态SQL</li></ul><h4 id="redis" tabindex="-1">Redis <a class="header-anchor" href="#redis" aria-label="Permalink to “Redis”">​</a></h4><ul><li>[ ] 数据类型和应用场景（字符串、哈希、列表、集合、有序集合）</li><li>[ ] 常见缓存问题的概念和解决思路（缓存穿透/击穿/雪崩——重点理解，不强求有大规模实战）</li><li>[ ] 持久化机制（RDB vs AOF）</li><li>[ ] 分布式锁实现（如基于 setnx / Redisson 的基本原理）</li></ul><h4 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to “MySQL”">​</a></h4><ul><li>[ ] 索引数据结构（B+树）</li><li>[ ] 索引失效场景</li><li>[ ] 事务隔离级别、MVCC</li><li>[ ] 慢查询分析和SQL优化</li></ul><h4 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to “Docker”">​</a></h4><ul><li>[ ] Docker和虚拟机的区别</li><li>[ ] Dockerfile常用指令</li><li>[ ] Docker网络模式</li><li>[ ] Docker Compose</li></ul><h3 id="项目准备" tabindex="-1">项目准备 <a class="header-anchor" href="#项目准备" aria-label="Permalink to “项目准备”">​</a></h3><ul><li>[ ] 每个项目能用STAR法则讲清楚</li><li>[ ] 每个项目准备1-2个技术亮点</li><li>[ ] 准备项目中的技术难点和解决方案</li><li>[ ] 准备可能被问到的技术问题</li></ul><h3 id="自我介绍" tabindex="-1">自我介绍 <a class="header-anchor" href="#自我介绍" aria-label="Permalink to “自我介绍”">​</a></h3><ul><li>[ ] 2-3分钟版本已背熟</li><li>[ ] 能流利说出技术栈和项目经验</li><li>[ ] 能自然把话题引导到自己最熟悉、准备最充分的项目和模块</li></ul><h3 id="其他准备" tabindex="-1">其他准备 <a class="header-anchor" href="#其他准备" aria-label="Permalink to “其他准备”">​</a></h3><ul><li>[ ] 熟悉简历上的每一句话</li><li>[ ] 准备反问面试官的问题</li><li>[ ] 测试面试环境（网络、摄像头、麦克风）</li></ul><hr><h2 id="💡-五、反问面试官的问题" tabindex="-1">💡 五、反问面试官的问题 <a class="header-anchor" href="#💡-五、反问面试官的问题" aria-label="Permalink to “💡 五、反问面试官的问题”">​</a></h2><ol><li><p><strong>&quot;这个岗位的主要技术栈是什么？团队用的是什么架构？&quot;</strong></p><ul><li>了解技术栈匹配度</li></ul></li><li><p><strong>&quot;这个岗位的主要挑战是什么？&quot;</strong></p><ul><li>了解工作内容和难度</li></ul></li><li><p><strong>&quot;团队有多少人？远程工作是怎么协作的？&quot;</strong></p><ul><li>了解团队规模和协作方式</li></ul></li><li><p><strong>&quot;作为有经验的开发者，我在哪些方面可以快速成长？&quot;</strong></p><ul><li>体现学习欲望</li></ul></li><li><p><strong>&quot;公司对远程开发有什么支持？比如设备、培训等？&quot;</strong></p><ul><li>了解远程工作的具体安排</li></ul></li></ol><hr><blockquote><p>💭 <strong>核心策略</strong>：小公司的技术面试更看重<strong>能干活、能独立解决问题</strong>的人。诚实、务实、突出优势、承认不足但强调学习能力。准备好技术细节，能回答深入问题。</p></blockquote>',76)])])}const g=i(t,[["render",e]]);export{c as __pageData,g as default};
